import React, { useEffect, useState } from 'react';
import api from '../data/api';
import { useAuth } from '../context/AuthContext';

const s = {
  page: { padding: '2rem', maxWidth: '700px', margin: '0 auto' },
  title: { fontSize: '1.8rem', fontWeight: 700, color: '#fff', marginBottom: '0.3rem' },
  sub: { color: '#888', marginBottom: '2rem' },
  row: { display: 'flex', alignItems: 'center', gap: '1rem', background: '#1a1a2e', border: '1px solid #2a2a4a', borderRadius: '10px', padding: '1rem 1.25rem', marginBottom: '0.75rem' },
  rank: { width: '2rem', textAlign: 'center', fontWeight: 700, fontSize: '1.1rem' },
  name: { flex: 1, color: '#e0e0e0', fontWeight: 500 },
  xp: { color: '#f7c948', fontWeight: 700 },
  streak: { color: '#ff9800', fontSize: '0.85rem' },
};

const rankColors = ['#f7c948', '#aaa', '#cd7f32'];

export default function Leaderboard() {
  const [users, setUsers] = useState([]);
  const { user } = useAuth();

  useEffect(() => { api.get('/leaderboard').then(r => setUsers(r.data)); }, []);

  return (
    <div style={s.page}>
      <div style={s.title}>🏆 Leaderboard</div>
      <div style={s.sub}>Top coders by XP</div>
      {users.map((u, i) => (
        <div key={u._id} style={{ ...s.row, borderColor: u._id === user?._id ? '#7c6af7' : '#2a2a4a' }}>
          <div style={{ ...s.rank, color: rankColors[i] || '#888' }}>
            {i < 3 ? ['🥇', '🥈', '🥉'][i] : i + 1}
          </div>
          <div style={s.name}>{u.name} {u._id === user?._id && <span style={{ color: '#7c6af7', fontSize: '0.8rem' }}>(you)</span>}</div>
          <div style={s.streak}>🔥 {u.streak}</div>
          <div style={s.xp}>⭐ {u.xp} XP</div>
        </div>
      ))}
    </div>
  );
}
